#include <stdio.h>
int main() {
    int n, sum, i, j;
    scanf("%d", &n);
    int coins[n];
    for (i = 0; i < n; i++) scanf("%d", &coins[i]);
    scanf("%d", &sum);
    int dp[sum + 1] = {0};
    dp[0] = 1;
    for (i = 0; i < n; i++) {
        for (j = coins[i]; j <= sum; j++) {
            dp[j] += dp[j - coins[i]];
        }
    }
    printf("%d\n", dp[sum]);
    return 0;
}

