const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let lines = [];
rl.on('line', (input) => {
    lines.push(input);
});
rl.on('close', () => {
    let n = parseInt(lines[0]);
    let coins = lines[1].split(' ').map(Number);
    let sum = parseInt(lines[2]);
    let dp = new Array(sum + 1).fill(0);
    dp[0] = 1;
    for (let i = 0; i < n; i++) {
        for (let j = coins[i]; j <= sum; j++) {
            dp[j] += dp[j - coins[i]];
        }
    }
    console.log(dp[sum]);
});
